/**
 * Checkbox 多选框组件
 * 支持多平台的多选框组件
 */

import { BaseComponent } from './BaseComponent';

export class Checkbox extends BaseComponent {
  /**
   * 构造函数
   * @param id 组件ID
   * @param props 组件属性
   */
  constructor(id: string, props: Record<string, any> = {}) {
    super(id, 'checkbox', props);
  }

  /**
   * 组件挂载后钩子
   */
  protected mounted(): void {
    this.initCheckboxElements();
    this.initCheckboxButtons();
  }

  /**
   * 初始化 Checkbox 元素
   */
  private initCheckboxElements(): void {
    const checkboxInputs = this.getElements('.t-checkbox__input');
    
    checkboxInputs.forEach(checkbox => {
      this.updateCheckedState(checkbox);
      
      this.addEventListener(checkbox, 'change', () => {
        this.updateCheckedState(checkbox);
        
        // 检查是否需要更新全选状态
        let parentGroup = this.getParent(checkbox);
        while (parentGroup) {
          if (parentGroup.dataset && parentGroup.dataset.checkboxGroup) {
            this.updateCheckAllState(`[data-checkbox-group="${parentGroup.dataset.checkboxGroup}"]`);
            break;
          }
          parentGroup = this.getParent(parentGroup);
        }
      });
    });
  }

  /**
   * 初始化 Checkbox Button 元素
   */
  private initCheckboxButtons(): void {
    const checkboxButtons = this.getElements('.t-checkbox-button');
    
    checkboxButtons.forEach(button => {
      this.addEventListener(button, 'click', () => {
        this.toggleButton(button);
      });
    });
  }

  /**
   * 更新 Checkbox 选中状态
   * @param checkbox checkbox输入元素
   */
  updateCheckedState(checkbox: any): void {
    const parent = this.getParent(checkbox);
    if (parent && parent.classList && parent.classList.contains && parent.classList.contains('t-checkbox')) {
      if (!parent.classList.contains('is-disabled')) {
        const isChecked = checkbox.checked;
        this.toggleClass(parent, 'is-checked', isChecked);
        this.setAttribute(parent, 'aria-checked', isChecked.toString());
        
        // 使用事件系统触发状态变化事件
        this.emit('t:checkbox:change', {
          value: checkbox.value,
          checked: isChecked,
          name: checkbox.name || 'default'
        });
      }
    }
  }

  /**
   * 切换 Checkbox Button 状态
   * @param button 按钮元素
   */
  toggleButton(button: any): void {
    if (button.classList && button.classList.contains && button.classList.contains('is-disabled')) {
      return;
    }
    
    const isActive = this.toggleClass(button, 'is-active');
    this.setAttribute(button, 'aria-pressed', isActive.toString());
    
    // 使用事件系统触发状态变化事件
    this.emit('t:checkbox:change', {
      value: button.dataset?.value || button.textContent,
      checked: isActive,
      name: 'button'
    });
  }

  /**
   * 切换 Checkbox Button 状态（兼容旧版调用方式）
   * @param button 按钮元素
   */
  toggleCheckboxButton(button: any): void {
    this.toggleButton(button);
  }

  /**
   * 切换全选状态（兼容旧版调用方式 - checkbox-cities-group）
   */
  toggleCheckAll(): void {
    // 兼容 checkbox.md 中的全选功能
    const allCheckbox = this.getElementById('checkbox-all-input');
    const cityCheckboxes = this.getElements('.city-checkbox');
    
    if (allCheckbox && cityCheckboxes.length > 0) {
      const isChecked = allCheckbox.checked;
      cityCheckboxes.forEach(cb => {
        cb.checked = !isChecked;
        this.updateCheckedState(cb);
      });
      allCheckbox.checked = !isChecked;
      this.updateCheckedState(allCheckbox);
      return;
    }
    
    // 如果没有找到特定元素，尝试使用通用的全选逻辑
    const allCheckboxEl = this.getElement('.t-checkbox.is-indeterminate, .t-checkbox[data-check-all]');
    if (allCheckboxEl) {
      let parentGroup = this.getParent(allCheckboxEl);
      while (parentGroup) {
        if (parentGroup.classList && parentGroup.classList.contains && parentGroup.classList.contains('t-checkbox-group')) {
          this.toggleCheckAllBySelector('#' + parentGroup.id);
          break;
        }
        parentGroup = this.getParent(parentGroup);
      }
    }
  }

  /**
   * 切换全选状态（通过选择器）
   * @param groupSelector 分组选择器
   */
  toggleCheckAllBySelector(groupSelector: string): void {
    const allCheckbox = this.getElement(`${groupSelector} .t-checkbox.is-indeterminate, ${groupSelector} [data-check-all]`);
    if (!allCheckbox) return;
    
    const allInput = allCheckbox.querySelector ? allCheckbox.querySelector('input[type="checkbox"]') : null;
    const itemCheckboxes = this.getElements(`${groupSelector} .t-checkbox:not([data-check-all]) input[type="checkbox"]`);
    
    if (allCheckbox.classList && allCheckbox.classList.contains && allCheckbox.classList.contains('is-indeterminate')) {
      this.removeClass(allCheckbox, 'is-indeterminate');
    }
    
    if (allInput) {
      allInput.checked = !allInput.checked;
      
      itemCheckboxes.forEach(checkbox => {
        checkbox.checked = allInput.checked;
        this.updateCheckedState(checkbox);
      });
      
      this.updateCheckedState(allInput);
    }
  }

  /**
   * 更新全选状态
   * @param groupSelector 分组选择器
   */
  updateCheckAllState(groupSelector: string): void {
    const allCheckbox = this.getElement(`${groupSelector} [data-check-all]`);
    if (!allCheckbox) return;
    
    const allInput = allCheckbox.querySelector ? allCheckbox.querySelector('input[type="checkbox"]') : null;
    const itemCheckboxes = this.getElements(`${groupSelector} .t-checkbox:not([data-check-all]) input[type="checkbox"]`);
    
    if (!allInput) return;
    
    const checkedCount = itemCheckboxes.filter(cb => cb.checked).length;
    const totalCount = itemCheckboxes.length;
    
    if (allCheckbox.classList) {
      this.removeClass(allCheckbox, 'is-indeterminate');
    }
    
    if (checkedCount === 0) {
      allInput.checked = false;
    } else if (checkedCount === totalCount) {
      allInput.checked = true;
    } else {
      allInput.checked = false;
      if (allCheckbox.classList) {
        this.addClass(allCheckbox, 'is-indeterminate');
      }
    }
    
    this.updateCheckedState(allInput);
  }

  /**
   * 通过ID获取元素
   * @param id 元素ID
   */
  private getElementById(id: string): any {
    return this.getElement(`#${id}`);
  }
}