/**
 * 基础组件类
 * 所有组件的基类，提供统一的接口和平台适配能力
 */

import type { Component } from '../core/interfaces';
import { PlatformManager } from '../platforms/PlatformManager';
import { EventEmitter } from '../core/EventEmitter';

export class BaseComponent implements Component {
  /**
   * 组件ID
   */
  id: string;

  /**
   * 组件类型
   */
  type: string;

  /**
   * 组件属性
   */
  props: Record<string, any> = {};

  /**
   * 组件状态
   */
  state: Record<string, any> = {};

  /**
   * 平台适配器
   */
  protected adapter = PlatformManager.getAdapter();

  /**
   * 事件发射器
   */
  protected eventEmitter = new EventEmitter();

  /**
   * 构造函数
   * @param id 组件ID
   * @param type 组件类型
   * @param props 组件属性
   */
  constructor(id: string, type: string, props: Record<string, any> = {}) {
    this.id = id;
    this.type = type;
    this.props = props;
  }

  /**
   * 组件生命周期钩子 - 创建前
   */
  protected beforeCreate(): void {
    // 创建前钩子，子类可以重写
  }

  /**
   * 组件生命周期钩子 - 创建后
   */
  protected created(): void {
    // 创建后钩子，子类可以重写
  }

  /**
   * 组件生命周期钩子 - 挂载前
   */
  protected beforeMount(): void {
    // 挂载前钩子，子类可以重写
  }

  /**
   * 组件生命周期钩子 - 挂载后
   */
  protected mounted(): void {
    // 挂载后钩子，子类可以重写
  }

  /**
   * 组件生命周期钩子 - 更新前
   */
  protected beforeUpdate(): void {
    // 更新前钩子，子类可以重写
  }

  /**
   * 组件生命周期钩子 - 更新后
   */
  protected updated(): void {
    // 更新后钩子，子类可以重写
  }

  /**
   * 组件生命周期钩子 - 销毁前
   */
  protected beforeDestroy(): void {
    // 销毁前钩子，子类可以重写
  }

  /**
   * 组件生命周期钩子 - 销毁后
   */
  protected destroyed(): void {
    // 销毁后钩子，子类可以重写
  }

  /**
   * 初始化组件（完整生命周期流程）
   */
  init(): void {
    // 执行创建阶段生命周期
    this.beforeCreate();
    this.created();
    this.beforeMount();
    
    // 基础初始化逻辑，子类可以在mounted中实现具体逻辑
    this.mounted();
  }

  /**
   * 销毁组件（完整生命周期流程）
   */
  destroy(): void {
    // 执行销毁阶段生命周期
    this.beforeDestroy();
    
    // 基础销毁逻辑，子类可以重写具体清理逻辑
    
    this.destroyed();
  }

  /**
   * 更新组件属性（带生命周期钩子）
   * @param props 新的属性
   */
  updateProps(props: Record<string, any>): void {
    // 更新前钩子
    this.beforeUpdate();
    
    this.props = { ...this.props, ...props };
    
    // 更新后钩子
    this.updated();
  }

  /**
   * 更新组件状态（带生命周期钩子）
   * @param state 新的状态
   */
  updateState(state: Record<string, any>): void {
    // 更新前钩子
    this.beforeUpdate();
    
    this.state = { ...this.state, ...state };
    
    // 更新后钩子
    this.updated();
  }

  /**
   * 获取元素
   * @param selector 选择器
   */
  protected getElement(selector: string): any {
    return this.adapter.querySelector(selector);
  }

  /**
   * 获取多个元素
   * @param selector 选择器
   */
  protected getElements(selector: string): any[] {
    return this.adapter.querySelectorAll(selector);
  }

  /**
   * 创建元素
   * @param tag 标签名
   * @param options 选项
   */
  protected createElement(tag: string, options: Record<string, any> = {}): any {
    return this.adapter.createElement(tag, options);
  }

  /**
   * 添加事件监听
   * @param element 元素
   * @param event 事件名
   * @param handler 事件处理函数
   */
  protected addEventListener(element: any, event: string, handler: Function): void {
    this.adapter.addEventListener(element, event, handler);
  }

  /**
   * 移除事件监听
   * @param element 元素
   * @param event 事件名
   * @param handler 事件处理函数
   */
  protected removeEventListener(element: any, event: string, handler: Function): void {
    this.adapter.removeEventListener(element, event, handler);
  }

  /**
   * 设置元素属性
   * @param element 元素
   * @param key 属性名
   * @param value 属性值
   */
  protected setAttribute(element: any, key: string, value: any): void {
    this.adapter.setAttribute(element, key, value);
  }

  /**
   * 获取元素属性
   * @param element 元素
   * @param key 属性名
   */
  protected getAttribute(element: any, key: string): string | null {
    return this.adapter.getAttribute(element, key);
  }

  /**
   * 添加样式类
   * @param element 元素
   * @param className 类名
   */
  protected addClass(element: any, className: string): void {
    this.adapter.addClass(element, className);
  }

  /**
   * 移除样式类
   * @param element 元素
   * @param className 类名
   */
  protected removeClass(element: any, className: string): void {
    this.adapter.removeClass(element, className);
  }

  /**
   * 切换样式类
   * @param element 元素
   * @param className 类名
   * @param force 是否强制添加/移除
   */
  protected toggleClass(element: any, className: string, force?: boolean): boolean {
    return this.adapter.toggleClass(element, className, force);
  }

  /**
   * 设置样式
   * @param element 元素
   * @param style 样式对象
   */
  protected setStyle(element: any, style: Record<string, any>): void {
    this.adapter.setStyle(element, style);
  }

  /**
   * 创建文本节点
   * @param text 文本内容
   */
  protected createTextNode(text: string): any {
    return this.adapter.createTextNode(text);
  }

  /**
   * 添加子元素
   * @param parent 父元素
   * @param child 子元素
   */
  protected appendChild(parent: any, child: any): void {
    this.adapter.appendChild(parent, child);
  }

  /**
   * 移除子元素
   * @param parent 父元素
   * @param child 子元素
   */
  protected removeChild(parent: any, child: any): void {
    this.adapter.removeChild(parent, child);
  }

  /**
   * 获取父元素
   * @param element 元素
   */
  protected getParent(element: any): any {
    return this.adapter.getParent(element);
  }

  /**
   * 获取子元素
   * @param element 元素
   */
  protected getChildren(element: any): any[] {
    return this.adapter.getChildren(element);
  }

  /**
   * 显示元素
   * @param element 元素
   */
  protected show(element: any): void {
    this.adapter.show(element);
  }

  /**
   * 隐藏元素
   * @param element 元素
   */
  protected hide(element: any): void {
    this.adapter.hide(element);
  }

  /**
   * 获取元素尺寸
   * @param element 元素
   */
  protected getBoundingClientRect(element: any): any {
    return this.adapter.getBoundingClientRect(element);
  }

  /**
   * 获取窗口尺寸
   */
  protected getWindowSize(): { width: number; height: number } {
    return this.adapter.getWindowSize();
  }

  /**
   * 动画
   * @param element 元素
   * @param props 属性
   * @param duration 持续时间
   * @param callback 回调函数
   */
  protected animate(element: any, props: Record<string, any>, duration: number, callback?: Function): void {
    this.adapter.animate(element, props, duration, callback);
  }

  /**
   * 定时器
   * @param callback 回调函数
   * @param delay 延迟时间
   */
  protected setTimeout(callback: Function, delay: number): number {
    return this.adapter.setTimeout(callback, delay);
  }

  /**
   * 清除定时器
   * @param timerId 定时器ID
   */
  protected clearTimeout(timerId: number): void {
    this.adapter.clearTimeout(timerId);
  }

  /**
   * 防抖函数
   * @param fn 函数
   * @param delay 延迟时间
   */
  protected debounce<T extends (...args: any[]) => any>(fn: T, delay: number): (...args: Parameters<T>) => void {
    return this.adapter.debounce(fn, delay);
  }

  /**
   * 节流函数
   * @param fn 函数
   * @param interval 间隔时间
   */
  protected throttle<T extends (...args: any[]) => any>(fn: T, interval: number): (...args: Parameters<T>) => void {
    return this.adapter.throttle(fn, interval);
  }

  /**
   * 订阅事件
   * @param eventName 事件名称
   * @param handler 事件处理函数
   */
  on(eventName: string, handler: Function): this {
    this.eventEmitter.on(eventName, handler);
    return this;
  }

  /**
   * 订阅事件（仅触发一次）
   * @param eventName 事件名称
   * @param handler 事件处理函数
   */
  once(eventName: string, handler: Function): this {
    this.eventEmitter.once(eventName, handler);
    return this;
  }

  /**
   * 取消订阅事件
   * @param eventName 事件名称
   * @param handler 事件处理函数（可选）
   */
  off(eventName: string, handler?: Function): this {
    this.eventEmitter.off(eventName, handler);
    return this;
  }

  /**
   * 发布事件
   * @param eventName 事件名称
   * @param args 事件参数
   */
  emit(eventName: string, ...args: any[]): boolean {
    return this.eventEmitter.emit(eventName, ...args);
  }

  /**
   * 获取事件监听器数量
   * @param eventName 事件名称
   */
  listenerCount(eventName: string): number {
    return this.eventEmitter.listenerCount(eventName);
  }

  /**
   * 获取所有事件名称
   */
  eventNames(): string[] {
    return this.eventEmitter.eventNames();
  }

  /**
   * 清除所有事件监听器
   */
  removeAllListeners(): this {
    this.eventEmitter.removeAllListeners();
    return this;
  }
}