/**
 * Web 平台适配器
 * 实现浏览器环境的 DOM 操作
 */

import type { PlatformAdapter, PlatformType } from '../core/interfaces';

export class WebAdapter implements PlatformAdapter {
  /**
   * 平台类型
   */
  platform: PlatformType = 'web';

  /**
   * 创建DOM元素
   * @param tag 标签名
   * @param options 选项
   */
  createElement(tag: string, options: Record<string, any> = {}): HTMLElement {
    const element = document.createElement(tag);
    
    // 设置属性
    if (options.className) {
      element.className = options.className;
    }
    
    if (options.id) {
      element.id = options.id;
    }
    
    if (options.style) {
      Object.assign(element.style, options.style);
    }
    
    if (options.attributes) {
      Object.entries(options.attributes).forEach(([key, value]) => {
        element.setAttribute(key, value);
      });
    }
    
    return element;
  }

  /**
   * 获取元素
   * @param selector 选择器
   */
  querySelector(selector: string): HTMLElement | null {
    return document.querySelector(selector);
  }

  /**
   * 获取多个元素
   * @param selector 选择器
   */
  querySelectorAll(selector: string): HTMLElement[] {
    return Array.from(document.querySelectorAll(selector));
  }

  /**
   * 添加事件监听
   * @param element 元素
   * @param event 事件名
   * @param handler 事件处理函数
   */
  addEventListener(element: HTMLElement, event: string, handler: EventListener): void {
    element.addEventListener(event, handler);
  }

  /**
   * 移除事件监听
   * @param element 元素
   * @param event 事件名
   * @param handler 事件处理函数
   */
  removeEventListener(element: HTMLElement, event: string, handler: EventListener): void {
    element.removeEventListener(event, handler);
  }

  /**
   * 设置元素属性
   * @param element 元素
   * @param key 属性名
   * @param value 属性值
   */
  setAttribute(element: HTMLElement, key: string, value: any): void {
    element.setAttribute(key, value);
  }

  /**
   * 获取元素属性
   * @param element 元素
   * @param key 属性名
   */
  getAttribute(element: HTMLElement, key: string): string | null {
    return element.getAttribute(key);
  }

  /**
   * 添加样式类
   * @param element 元素
   * @param className 类名
   */
  addClass(element: HTMLElement, className: string): void {
    element.classList.add(className);
  }

  /**
   * 移除样式类
   * @param element 元素
   * @param className 类名
   */
  removeClass(element: HTMLElement, className: string): void {
    element.classList.remove(className);
  }

  /**
   * 切换样式类
   * @param element 元素
   * @param className 类名
   * @param force 是否强制添加/移除
   */
  toggleClass(element: HTMLElement, className: string, force?: boolean): boolean {
    return element.classList.toggle(className, force);
  }

  /**
   * 设置样式
   * @param element 元素
   * @param style 样式对象
   */
  setStyle(element: HTMLElement, style: Record<string, any>): void {
    Object.assign(element.style, style);
  }

  /**
   * 创建文本节点
   * @param text 文本内容
   */
  createTextNode(text: string): Text {
    return document.createTextNode(text);
  }

  /**
   * 添加子元素
   * @param parent 父元素
   * @param child 子元素
   */
  appendChild(parent: HTMLElement, child: Node): void {
    parent.appendChild(child);
  }

  /**
   * 移除子元素
   * @param parent 父元素
   * @param child 子元素
   */
  removeChild(parent: HTMLElement, child: Node): void {
    parent.removeChild(child);
  }

  /**
   * 获取父元素
   * @param element 元素
   */
  getParent(element: HTMLElement): HTMLElement | null {
    return element.parentElement;
  }

  /**
   * 获取子元素
   * @param element 元素
   */
  getChildren(element: HTMLElement): HTMLElement[] {
    return Array.from(element.children);
  }

  /**
   * 显示元素
   * @param element 元素
   */
  show(element: HTMLElement): void {
    element.style.display = '';
  }

  /**
   * 隐藏元素
   * @param element 元素
   */
  hide(element: HTMLElement): void {
    element.style.display = 'none';
  }

  /**
   * 获取元素尺寸
   * @param element 元素
   */
  getBoundingClientRect(element: HTMLElement): DOMRect {
    return element.getBoundingClientRect();
  }

  /**
   * 获取窗口尺寸
   */
  getWindowSize(): { width: number; height: number } {
    return {
      width: window.innerWidth,
      height: window.innerHeight,
    };
  }

  /**
   * 动画
   * @param element 元素
   * @param props 属性
   * @param duration 持续时间
   * @param callback 回调函数
   */
  animate(element: HTMLElement, props: Record<string, any>, duration: number, callback?: Function): void {
    Object.assign(element.style, {
      transition: `all ${duration}ms ease`,
    });
    
    Object.assign(element.style, props);
    
    setTimeout(() => {
      element.style.transition = '';
      callback?.();
    }, duration);
  }

  /**
   * 定时器
   * @param callback 回调函数
   * @param delay 延迟时间
   */
  setTimeout(callback: Function, delay: number): number {
    return window.setTimeout(callback, delay);
  }

  /**
   * 清除定时器
   * @param timerId 定时器ID
   */
  clearTimeout(timerId: number): void {
    window.clearTimeout(timerId);
  }

  /**
   * 防抖函数
   * @param fn 函数
   * @param delay 延迟时间
   */
  debounce<T extends (...args: any[]) => any>(fn: T, delay: number): (...args: Parameters<T>) => void {
    let timer: number | null = null;
    
    return function(...args: Parameters<T>) {
      if (timer) {
        clearTimeout(timer);
      }
      
      timer = setTimeout(() => {
        fn.apply(this, args);
      }, delay);
    };
  }

  /**
   * 节流函数
   * @param fn 函数
   * @param interval 间隔时间
   */
  throttle<T extends (...args: any[]) => any>(fn: T, interval: number): (...args: Parameters<T>) => void {
    let lastTime = 0;
    
    return function(...args: Parameters<T>) {
      const now = Date.now();
      
      if (now - lastTime >= interval) {
        lastTime = now;
        fn.apply(this, args);
      }
    };
  }
}